"use client";

import { useMemo, useState } from "react";
import { ArrowRight } from "lucide-react";
import { Button, Card } from "@/components/ui";

function formatVND(n: number) {
  return new Intl.NumberFormat("vi-VN").format(Math.round(n)) + " ₫";
}

export function LoanCalculator() {
  const [amount, setAmount] = useState(500_000_000);
  const [term, setTerm] = useState(24);
  const rate = 0.089; // 8.9% APR

  const { monthly, totalInterest } = useMemo(() => {
    const r = rate / 12;
    const m = (amount * r) / (1 - Math.pow(1 + r, -term));
    return { monthly: m, totalInterest: m * term - amount };
  }, [amount, term]);

  return (
    <Card className="relative z-10 mx-auto w-full max-w-5xl -mt-8 border-border/60 p-6 shadow-elevated md:-mt-16 md:p-8">
      <div className="grid gap-8 md:grid-cols-5">
        <div className="space-y-6 md:col-span-3">
          <div>
            <div className="mb-3 flex items-center justify-between">
              <label htmlFor="loan-amount" className="text-sm font-semibold text-navy">
                Số tiền vay
              </label>
              <span className="text-sm font-bold text-brand">{formatVND(amount)}</span>
            </div>
            <input
              id="loan-amount"
              type="range"
              className="loan-range"
              min={50_000_000}
              max={5_000_000_000}
              step={10_000_000}
              value={amount}
              onChange={(e) => setAmount(Number(e.target.value))}
              aria-valuemin={50_000_000}
              aria-valuemax={5_000_000_000}
              aria-valuenow={amount}
              aria-valuetext={formatVND(amount)}
            />
            <div className="mt-1 flex justify-between text-xs text-muted-foreground">
              <span>50 triệu</span>
              <span>5 tỷ</span>
            </div>
          </div>

          <div>
            <div className="mb-3 flex items-center justify-between">
              <label htmlFor="loan-term" className="text-sm font-semibold text-navy">
                Thời gian vay
              </label>
              <span className="text-sm font-bold text-brand">{term} tháng</span>
            </div>
            <input
              id="loan-term"
              type="range"
              className="loan-range"
              min={6}
              max={240}
              step={6}
              value={term}
              onChange={(e) => setTerm(Number(e.target.value))}
              aria-valuemin={6}
              aria-valuemax={240}
              aria-valuenow={term}
              aria-valuetext={`${term} tháng`}
            />
            <div className="mt-1 flex justify-between text-xs text-muted-foreground">
              <span>6 tháng</span>
              <span>240 tháng</span>
            </div>
          </div>
        </div>

        <div className="flex flex-col justify-between rounded-xl bg-cream p-5 md:col-span-2">
          <div className="space-y-4">
            <div>
              <p className="text-xs uppercase tracking-wider text-muted-foreground">
                Ước tính hàng tháng
              </p>
              <p className="mt-1 text-2xl font-extrabold text-navy">{formatVND(monthly)}</p>
            </div>
            <div>
              <p className="text-xs uppercase tracking-wider text-muted-foreground">
                Tổng tiền lãi
              </p>
              <p className="mt-1 text-lg font-semibold text-navy">{formatVND(totalInterest)}</p>
            </div>
            <p className="text-[11px] text-muted-foreground">
              Lãi suất tham khảo 8.9%/năm. Kết quả chỉ mang tính minh họa.
            </p>
          </div>
          <Button className="mt-4 h-11 w-full bg-brand font-semibold text-on-primary shadow-sm hover:bg-brand-hover">
            Đăng ký ngay
            <ArrowRight className="ml-1 h-4 w-4" />
          </Button>
        </div>
      </div>
    </Card>
  );
}

