          {SECTION_LINKS.map((l) => (
            <button
              key={l.id}
              type="button"
              onClick={() => handleSectionClick(l.id)}
              className="text-sm font-medium tracking-wide text-navy transition-colors hover:text-brand"
            >
              {t.nav[l.key]}
            </button>
          ))}
        </nav>
        <div className="flex items-center gap-2">
          <div
            className="mr-1 hidden items-center text-xs font-medium md:flex"
            role="group"
            aria-label="Language"
