            <Menu className="h-5 w-5" />
          </button>
        </div>
      </div>
      {open && (
        <div className="flex flex-col gap-3 border-t border-border bg-background px-4 py-3 lg:hidden">
          {SECTION_LINKS.map((l) => (
            <button
              key={l.id}
